import { AsyncStorage } from 'react-native';

const API_URL = 'https://api.example.com';
const AUTH_HEADER_KEY = 'Authorization';

export const login = async (username, password) => {
  try {
    const response = await fetch(`${API_URL}/login`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ username, password })
    });

    if (!response.ok) {
      throw new Error('Invalid credentials');
    }

    const data = await response.json();
    await AsyncStorage.setItem(AUTH_HEADER_KEY, `Bearer ${data.token}`);
    return data;
  } catch (error) {
    console.error(error);
    throw error;
  }
};

export const fetchUserProfile = async () => {
  try {
    const token = await AsyncStorage.getItem(AUTH_HEADER_KEY);
    if (!token) {
      throw new Error('No token found');
    }

    const response = await fetch(`${API_URL}/profile`, {
      headers: {
        [AUTH_HEADER_KEY]: token
      }
    });

    if (!response.ok) {
      throw new Error('Failed to fetch profile');
    }

    return response.json();
  } catch (error) {
    console.error(error);
    throw error;
  }
};

export const updateUserData = async (dataToUpdate) => {
  try {
    const token = await AsyncStorage.getItem(AUTH_HEADER_KEY);
    if (!token) {
      throw new Error('No token found');
    }

    const response = await fetch(`${API_URL}/updateProfile`, {
      method: 'PUT',
      headers: {
        [AUTH_HEADER_KEY]: token,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(dataToUpdate)
    });

    if (!response.ok) {
      throw new Error('Failed to update profile');
    }

    return response.json();
  } catch (error) {
    console.error(error);
    throw error;
  }
};